import json
from pathlib import Path

SKILL_DATA = Path(__file__).parent / "skill_data"

def _cm_success(action, message=None, data=None):
    return { 'ok': True, 'action': action, 'message': message or f'{action} successful', 'data': data or {} }

def add(key, value):
    skill_data = json.loads(SKILL_DATA.read_text()) if SKILL_DATA.exists() else {}
    skill_data[key] = value
    SKILL_DATA.write_text(json.dumps(skill_data))
    return _cm_success('add', data={'key': key, 'value': value})

def get(key):
    skill_data = json.loads(SKILL_DATA.read_text()) if SKILL_DATA.exists() else {}
    value = skill_data.get(key)
    return _cm_success('get', data={'key': key, 'value': value})

def remove(key):
    skill_data = json.loads(SKILL_DATA.read_text()) if SKILL_DATA.exists() else {}
    value = skill_data.pop(key, None)
    SKILL_DATA.write_text(json.dumps(skill_data))
    return _cm_success('remove', data={'key': key, 'value': value})
